    void unpin() {
        int remaining = pins.decrementAndGet();
        if (remaining < 0) {
            throw new IllegalStateException("Pin count underflow for revision " + revision());
        }
        if (remaining == 0 && cooled.get()) {
            closeLoadedGeneration();
        }
